                'map_link' => '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d60445.34024164738!2d95.1736351449663!3d18.76096091118147!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x30c778391d332a93%3A0x83b4dbc0764025fa!2sShwe%20Myet%20Mhan%20Buddhist%20Temple!5e0!3m2!1sen!2smm!4v1719574371101!5m2!1sen!2smm" width="600" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>',
