                'map_link' => '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3778.8838975922913!2d95.13371978573753!3d18.714015417916823!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x30c77f00202aa6e1%3A0x65cd6aab7744b83b!2z4YCV4YCx4YCr4YC64YCQ4YCx4YCs4YC64YCZ4YCwIOGAm-GAvuGAhOGAuuGAluGAvOGAsCDhgJjhgK_hgJvhgKzhgLg!5e0!3m2!1sen!2smm!4v1719572802112!5m2!1sen!2smm" width="600" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>',
