        'map_link' => '<iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d1945897.7253102672!2d94.30293422525125!3d17.71721960505844!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x30c033fc1b3ad3e7%3A0xfe3beb55db589bf4!2sShwe%20Bhone%20Myint%20Pagoda!5e0!3m2!1sen!2smm!4v1721630730427!5m2!1sen!2smm" width="600" height="450" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="no-referrer-when-downgrade"></iframe>',
        'website' => '',
        'address' => 'ဧရာဝတီတိုင်းဒေသကြီး၊ မအူပင်ခရိုင်၊ မအူပင်မြို့။',
        'history' => "(ရည်ညွှန်းစာ : ကွန်ပျူတာတက္ကသိုလ်(ပုသိမ်)မှ ပေးပို့လာသော မှတ်တမ်းမှ ကူးယူဖော်ပြထားခြင်းဖြစ်ပါသည်။)\n\nဧရာဝတီတိုင်းဒေသကြီး၊ မအူပင်ခရိုင်၊ မအူပင်မြို့၏ ကျက်သရေဆောင် ရွှေဘုန်းမြင့်စေတီတော် မြတ်ကြီးကို ၁၂၅၂ ခု၊ တန်ခူးလပြည့်၊ တနင်္လာနေ့နံနက်အချိန်တွင် မအူပင်မြို့၊ နန္ဒာဇေယျကုန်း တော်၌ လက်မွန်အစ ပထမ ပန္နက်သဲစိုက်၍ တည်ခဲ့ရာ ၁၂၆၁ခုနှစ်၊ နတ်တော်လပြည့်ကျော်(၇) ရက်၊ စနေနေ့တွင် အုတ်ရိုးစေတီတော်ကြီး အပြီးသတ်သည်။ ၁၂၆၁ ခုနှစ်၊ တပို့တွဲလပြည့် အင်္ဂါနေ့တွင် လောဟမယထီးတော်ကြီးကို တင်လျှက် စေတီတော်ကြီး အပြီးအဆုံးသို့ ရောက်စေခဲ့သည်။\n( လောဟမယထီးတော်ကြီးမှာ ဘုံကိုးဆင့်ရှိ သံထီး ဖြစ်သည်။)\nစေတီတော်၏ ကုန်းတော်အကျယ်မှာ စတုရန်း ၄၄၀ တောင်၊ ကုန်းတော်အမြင့် ၅ တောင်၊  ဉာဏ်တော် အမြင့် ၇၃ တောင် ရှိပါသည်။\n",
        'status' => 'local'
