                'history' => '(ရည်ညွှန်းစာ  :   ရတနာသီရိမဟာဘုရားကြီးစေတီတော် ဂေါပကအဖွဲ့မှ ပေးပို့ထားသော မှတ်တမ်းမှ ကူးယူဖော်ပြထားခြင်း ဖြစ်ပါသည်။)                \r\n   \r\n\r\n           ရတနာသီရိမဟာဘုရားကြီး စေတီတော်မြတ်ကြီးသည် သရေခေတ္တရာမြို့ဟောင်း၏ အနောက်မြောက်ဘက် ပြည်အောင်လံ ကားလမ်းမဘေးတွင် တည်ရှိပါသည်။ အစဉ်အလာပြောဆိုမှု များနှင့် မြန်မာရာဇဝင်ကျမ်းအချို့တွင် ဒွတ္တဘောင်မင်း တည်ထားခဲ့သော စေတီကိုးဆူအနက် တစ်ဆူအပါအဝင် ဖြစ်ပါသည်။ မြတ်စွာဘုရားရှင်၏ ဓာတ်တော်စစ်တစ်ဆူ လက်ယာခြေမတော်မှ ခြေသည်းတော်ကို ထည့်သွင်းဌာပနာထားကာ မဟာစေတီဟု သမုတ်၍ တည်ထားခဲ့ကြောင်း စေတီတည်ထားစဉ်က ဖြေးဖြေးဆေးဆေး တည်တော်မူပါသဖြင့် ဆေးဆေးစေတီဟု လည်းကောင်း၊ အလွန်ကြီးမားသောကြောင့် မဟာစေတီဟုလည်းကောင်း ယခုအချိန်အခါတွင် ရတနာသီရိမဟာ ဘုရားကြီးစေတီတော်မြတ်ကြီးဟု ခေါ်ဆိုသည်။\r\nရတနာသီရိမဟာဘုရားကြီး စေတီတော်မြတ်ကြီး စေတီ၏ ပုံသဏ္ဌာန်သည် အခြေ၌ ပြောင်းရှည်ပုံသဏ္ဌာန်ရှိပြီး အပေါ်သို့ ကန်တော့ပုံ တဖြည်းဖြည်းခုံးသွားသော ပုံသဏ္ဌာန်ဖြစ်သည်။ ၎င်းစေတီသည် မူလက်ရာဖြစ်ပြီး အုတ်နှင့်ထုံးသရွတ်များ စေတီ၏မျက်နှာပြင် တွင် ကျန်ရှိနေသေးကြောင်း တွေ့ရှိရပါသည်။ ပစ္စယာ(၄)ဆင့် ပါရှိပြီး ထောင့်(၁၆)ထောင့်ပါသော ပစ္စယာ(၃)ဆင့်နှင့် ထိပ်ဆုံးပစ္စယာမှာ အဝိုင်းပုံသဏ္ဌာန် ရှိသည်။ ဘုရားကြီးစေတီ၏အမြင့်မှာ (၁၃၉)ပေရှိပြီး လုံးပတ်မှာ (၃၀၇)ပေရှိသည်။ ဘုရားကြီးစေတီသည် မြန်မာနိုင်ငံအတွင်း စေတီ တည်ထားကိုးကွယ်မှုအပိုင်းတွင် အစောဆုံးထဲ၌ အပါအဝင်ဖြစ်ပြီး ပျူခေတ်အလယ်ပိုင်း (အေဒီ  ၄ - ၇ ရာစု)တွင် တည်ထားခဲ့သော စေတီတစ်ဆူ ဖြစ်ပါသည်။ ၎င်းသည် မျက်မှောက်ခေတ်စေတီများ၏ ရှေ့ပြေးပုံစံ အသွင်မျိုးဖြစ်သည်။ ဘုရားကြီးစေတီသည် ပျူလူမျိုးတို့၏ ယုံကြည်ကိုးကွယ်မှု အယူဝါဒများထဲမှ ဗုဒ္ဓဘာသာရေးနှင့် ဆက်စပ်နေသော အဆောက်အအုံဖြစ်သောကြောင့် ကမ္ဘာ့အမွေအနှစ်စံညွှန်းအဖြစ် သတ်မှတ်ခဲ့ခြင်းဖြစ်ပါသည်။ (၁၉၁၁-၁၉၁၂)နှင့် (၁၉၁၂-၁၉၁၃)ခုနှစ် တွင် ဘုရားကြီးစေတီ၏ တောင်ဘက်အနီးတွင် ကျောက်အရိုးအိုးလေးလုံးနှင့် မြေအရိုးအိုးတစ်လုံး တူးဖော်ရရှိခဲ့ပါသည်။ ထိုအရိုးအိုးများပေါ်၌ ပျူစာများ ရေးထိုးထားပြီး ထိုစာများအရ ၎င်းအရိုးအိုး များသည် သရေခေတ္တရာတွင် စိုးစံခဲ့သော ဟရိစိတြမင်း၊ သီဟဝိကြမမင်း၊ သူရိယဝိကြမမင်းတို့၏ အရိုးအိုးများဖြစ်ကြောင်း သိရှိခဲ့ရသည်။',
                'status' => 'famous',
            ],
            [
                'name' => 'ဘုရားမာစေတီ',
                'division_name' => 'ပဲခူးတိုင်းဒေသကြီး',
                'district_name' => 'ပြည်ခရိုင်',
                'township_name' => 'ပြည်မြို့နယ်',
                'photo' => 'images/ဘုရားမာ.jpg',
                'map_link' => '<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3776.184539738246!2d95.29942607593966!3d18.834460759509422!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x30c79bfa313fffff%3A0xd8a02e70817f2179!2sPhaya%20Mar%20Pagoda!5e0!3m2!1sen!2smm!4v1718178987555!5m2!1sen!2smm\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>',
                'website' => '',
                'address' => 'ပြည်-ပေါက်ခေါင်း လမ်းမကြီးဘေး ၊ ပြည်မြို့။',
                'history' => '(ရည်ညွှန်းစာ : ရှေးဟောင်းသုတေသနနှင့် အမျိုးသားပြတိုက်ဦးစီးဌာနမှ ပေးပို့ထားသော မှတ်တမ်းမှ ကူးယူဖော်ပြထားပါသည်။)\r\n\r\n          ဘုရားမာစေတီကို သရေခေတ္တရာမြို့ဟောင်း၏ အရှေ့မြောက်ဘက် ပြည်-ပေါက်ခေါင်း ကားလမ်းနံဘေး၊ ကုန်းရိုးကျေးရွာအနီးတွင် တည်ရှိပါသည်။ အစဉ်အလာ ပြောဆိုမှုများနှင့် မြန်မာရာဇဝင်ကျမ်းအချို့တွင် စေတီတော်၌ ဘုရားရှင်၏ဓာတ်တော်နှင့် လက်သည်းတော်၊ ခြေသည်းတော်၊ ညှပ်ရိုးတော်တို့ကို ဌာပနာထား၍ တည်ထား ကိုးကွယ်ခဲ့သော စေတီတစ်ဆူဖြစ်ကြောင်း သိရှိရပါသည်။ ရှေးယခင်က “သရိုင်မာ” စေတီဟု ခေါ်ဝေါ်ခဲ့ကြပြီး အေဒီ(၆-၇)ရာစုတွင် ဒွတ္တဘောင်မင်းကြီးမှ တည်ထားခဲ့သော ဉာဏ်တော် အမြင့် (၁၃၈)ပေရှိသည့် စေတီတစ်ဆူဖြစ်ပါသည်။ ဘုရားမာစေတီကြီး၏ ဗိသုကာပုံစံမှာ ကြီးမားမတ်စောက်သော ခေါင်းလောင်းပုံစံရှိပြီး ထိပ်ပိုင်းတွင် ခရေသီးပါရှိ၍ ထီးတော်တင် ထားသည်။ ပစ္စယာလေးဆင့်ပါရှိပြီး ထောင့်(၁۶)မြှောင့်ပါသော ပစ္စယာ(၃)ဆင့်နှင့် စတုတ္ထ ပစ္စယာမှာ အဝိုင်းပုံစံဖြစ်ပါသည်။ ဘုရားမာစေတီတော်ကြီးကို အုတ်ဖြင့်ဂင်းပိတ်ပုံစံ အဆင်တန်ဆာမရှိဘဲ ရိုးရိုးရှင်းရှင်း တည်ဆောက်ထားပါသည်။',
                'status' => 'famous',
            ],

        ];
    }

    // Logic ကို ခွဲထုတ်ထားတဲ့အတွက် Run ရတာ ပိုရှင်းသွားပါတယ်
    private function seedPagoda(array $data): void
    {
        $district = District::where('name', 'LIKE', '%'.$data['district_name'].'%')->first();
        if (! $district) {
            return;
        }

        $township = Township::where('name', 'LIKE', '%'.$data['township_name'].'%')
            ->where('district_id', $district->id)
            ->first();

        if ($township) {
            Pagoda::updateOrCreate(
                ['name' => $data['name']],
                [
                    'township_id' => $township->id,
                    'photo' => $data['photo'],
                    'map_link' => $data['map_link'],
                    'website' => $data['website'],
                    'address' => $data['address'],
                    'history' => $data['history'],
                    'status' => $data['status'],
                ]
            );
        }
    }
}
